window.__QUIZ_DATA__=[{"id":"objective>Physics>2022>1","subject":"Physics","year":"2022","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF WORK","question":"The area under a force-time graph represents","images":[],"options":{"A":"change in kinetic energy","B":"change in momentum","C":"workdone","D":"change in initial energy"},"answer":"B","explanation":"The area under a force-time graph represents the change in momentum. This is because the area under a force-time graph is equal to the integral of force with respect to time, which is the impulse. Impulse is equal to the change in momentum, according to the impulse-momentum theorem.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>2","subject":"Physics","year":"2022","type":"Objective","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: LAW OF FLOTATION","question":"From the principle of flotation, a body sinks in a fluid until it displaces a quantity of fluid equal to its own.","images":[],"options":{"A":"density","B":"mass","C":"weight","D":"volume"},"answer":"C","explanation":"Principle of flotation states that a floating object displaces a weight of fluid equal to its own weight.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2022>3","subject":"Physics","year":"2022","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"Suppose three identical steel balls Q, R and S are placed on an undulating ground as illustrated in the diagram above. Which of the balls is/are in neutral equilibrium?","images":["data:image/png;base64,"],"options":{"A":"S only","B":"Q only","C":"R only","D":"Q and S only"},"answer":"B","explanation":"A body is said to be in a neutral equilibrium if when slightly displaced, it tends to come to rest in its new position.  If Q is slightly displced it comes to rest at the lowest point of the surface, S is in a stable equilibrium, it will return to its position if it is displaced, while R is in an unstable equilibrium.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>4","subject":"Physics","year":"2022","type":"Objective","topic":"SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M","question":"The length of a simple pendulum is increased by a factor of four. By what factor is its period increased?","images":[],"options":{"A":"0.5\u03c0","B":"2","C":"2\u03c0","D":"4"},"answer":"B","explanation":"T = 2\u03c0 \u221aL/g  if L2 = 4L  T2 = 2\u03c0 \u221a4L/g  T2 = 2\u03c0 \u221a4(\u221aL/g)  T2 = 2(2\u03c0 \u221aL/g)  T2 = 2T","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>5","subject":"Physics","year":"2022","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"The linear expansivity, \u03b1, and the cubic expansivity, \u03b3, of a material are related by the equation.","images":[],"options":{"A":"\u03b3 = \u03b1","B":"\u03b3 = 3\u03b1","C":"\u03b3 = 2\u03b1","D":"\u03b3 = 1/3\u03b1"},"answer":"B","explanation":"The cubic expansivity (\u03b3) of a material is three times its linear expansivity (\u03b1). This is because cubic expansivity is the change in volume of a material per unit original volume per degree Celsius rise in temperature, while linear expansivity is the change in length per unit original length per degree Celsius rise in temperature. Since volume is a three-dimensional quantity (length, width, and height), the cubic expansivity is three times the linear expansivity.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>6","subject":"Physics","year":"2022","type":"Objective","topic":"RECTILINEAR ACCELERATION : VELOCITY-TIME GRAPH","question":"Which of  the illustrated graphs below represents a body moving with uniform retardation?","images":["data:image/jpeg;base64,","data:image/jpeg;base64,","data:image/jpeg;base64,","data:image/jpeg;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"D","explanation":"The inital velocity(velocity at t=0) is higher than the final velocity.   Decrease in velocity = retardation","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>7","subject":"Physics","year":"2022","type":"Objective","topic":"MOTION : TYPES OF MOTION","question":"The correct relationship between the displacement, s, of a particle initially at rest in a linear motion and the time, t, is","images":[],"options":{"A":"s \u221d t-2","B":"s \u221d t-1","C":"s \u221d t","D":"s \u221d t2"},"answer":"D","explanation":"Second equation of motion   s = ut + 1/2at2  u= 0, a=constant  s= 1/2at2  s \u221dt2","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>8","subject":"Physics","year":"2022","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF WORK","question":"The Joule is equivalent to","images":[],"options":{"A":"kgm2s-1","B":"kg2ms-2","C":"kgm2s-2","D":"kgms-1"},"answer":"C","explanation":"joule is the unit for workdone  workdone = force x distance  force = mass x acceleration = kg x ms-2  distance = m  joule = kgms-2 x m  kgm2s-2","marks":"1","difficulty":"1"},{"id":"objective>Physics>2022>9","subject":"Physics","year":"2022","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"Which of the following statement(s) is/are correct about  a fixed mass of gas compressed in an inexpansible container?  i. The average speed of the molecules increases  ii. The temperature of the gas increases  iii.The molecules hit the walls of the container more often than before the compression.","images":[],"options":{"A":"i only","B":"i and ii only","C":"i and iii only","D":"i,ii and iii"},"answer":"D","explanation":"If a gas is compressed, it means pressure is increased. Since pressure is directly proportional to temperature, the temperature increases, then there is also an increase in speed which means they hit the wall of the container faster.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>10","subject":"Physics","year":"2022","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : PRODUCTION AND PROPAGATION OF MECHANICAL WAVES","question":"An example of a mechanical wave is","images":[],"options":{"A":"water waves","B":"radio waves","C":"x-rays","D":"light rays"},"answer":"A","explanation":"Mechanical waves are waves that transfer energy through a medium e.g water waves, sound waves, spring waves, etc.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2022>11","subject":"Physics","year":"2022","type":"Objective","topic":"LIGHT WAVES : PLANE MIRROR","question":"Which of the following descriptions of the image formed  by a plane mirror is not correct?  The image is","images":[],"options":{"A":"erect and of the same size as the object","B":"laterally inverted and of the same size as the object","C":"erect and bigger than the object","D":"virtual and of the same size as the object"},"answer":"C","explanation":"Image formed by a plane mirror is  i. virtual and erect  ii. laterally inverted  iii.of same size as the object  iv. formed at the same distance behind the mirror as the distance of the object in front of the mirror","marks":"1","difficulty":"1"},{"id":"objective>Physics>2022>12","subject":"Physics","year":"2022","type":"Objective","topic":"MACHINES :","question":"The efficiency of a wheel and axle is 100% and the ratio of their radii is 5:1. Calculate the effort required to lift a load of mass 20kg using this machine. [g = 10ms-2]","images":[],"options":{"A":"20N","B":"25N","C":"40N","D":"100N"},"answer":"C","explanation":"M.A of wheel and axle = R/r  R/r = 5:1  M.A = 5  M.A = load/effort  load = mg = 20kg x 10 ms-2= 200N  effort = Load/M.A  effort = 200N/5   effort = 40N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>13","subject":"Physics","year":"2022","type":"Objective","topic":"MAGNETIC FIELD : THE EARTH\u2019S MAGNETIC FIELD","question":"A freely suspended compass needle on the earth's surface settles in a plane called","images":[],"options":{"A":"geographic meridian","B":"magnetic meridian","C":"magnetic declination","D":"isoganals"},"answer":"B","explanation":"Magnetic meridian is a line on the earth's surface approximating a great circle passing through the north and south magnetic poles.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>14","subject":"Physics","year":"2022","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"An object is placed at different distances,u, from a converging lens of focal length, 15.0cm. For what value of u does the lens act as a simple microscope?","images":[],"options":{"A":"u = 15cm only","B":"u = 30cm only","C":"u","D":"u > 30cm only"},"answer":"C","explanation":"For a converging lens to act as a simple microscope, the object must be placed at a distance less than one focal length.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>15","subject":"Physics","year":"2022","type":"Objective","topic":"SOUND WAVES : BEATS","question":"The periodic rise and fall in the intensity of sound produced when two notes of nearly equal frequencies are sounded together is called","images":[],"options":{"A":"doppler effect","B":"beat","C":"interference","D":"resonance"},"answer":"B","explanation":"Beats are the periodic and repeating fluctuations heard in the intensity of a sound when two sound waves of very similar frequencies interfere with one another.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>16","subject":"Physics","year":"2022","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The power of a lens is +2.5 D. What is its radius of curvature ?","images":[],"options":{"A":"2.5 cm","B":"25.0 cm","C":"40.0 cm","D":"80.0 cm"},"answer":"D","explanation":"Power of lens(P) = 1/f  f = 1/P  f = 1/2.5  f = 0.4m = 40cm  f = radius of curvature(r)/2  r = 2f  r = 2 x 40cm  r = 80cm","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>17","subject":"Physics","year":"2022","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"The reason for having a large number of turns in the coil of a moving coil galvanometer is to","images":[],"options":{"A":"make the deflection of the needle proportional to the current","B":"increase the sensitivity of the galvanometer","C":"decrease the magnetic flux produced by the magnet","D":"make the permanent magnet stronger"},"answer":"B","explanation":"The sensitivity of a galvanometer is directly proportional to the number of turns in the coil. More turns mean a greater magnetic effect for a given current, which allows the galvanometer to detect smaller currents.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>18","subject":"Physics","year":"2022","type":"Objective","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"Current is passed through two parallel conductors in the same direction. If the conductors are placed near each other, they will","images":[],"options":{"A":"move in a circle","B":"repel each other","C":"remain stationary","D":"attract each other"},"answer":"D","explanation":"If current is passed through two parallel conductors in the same direction, they will attract each other due to magnetic force between them","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>19","subject":"Physics","year":"2022","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"The period of a 10kHZ radio wave travelling at 3.0 x 108 ms-1 is","images":[],"options":{"A":"3.0 x 10-5 s.","B":"1.0 x 10-4 s.","C":"1.0 x 104 s.","D":"3.0 x 104 s."},"answer":"B","explanation":"period (T) = 1/f, 10kHz = 104Hz  T = 1/104s  T = 10-4s  T = 1.0 x 10-4s","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>20","subject":"Physics","year":"2022","type":"Objective","topic":"MAGNETIC MATERIALS :","question":"The magnetic material produced from the chemical combination of metal oxides and has a very high resistance to electric current is called a","images":[],"options":{"A":"ferrite substance","B":"paramagnetic substance","C":"ferromagnetic substance","D":"diamagnetic substance"},"answer":"A","explanation":"Ferrite substances are magnetic materials produced from the chemical combination of metal oxides. They have a very high resistance to electric current. Ferrites are used in many technological applications, including the cores of electrical transformers, magnetic cores of electrical inductors, and in the production of magnets.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>21","subject":"Physics","year":"2022","type":"Objective","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"A body of mass, M, moving with velocity, V, has a wavelength, \u03bb, associated with it. This phenomenon is called","images":[],"options":{"A":"photoelectric effect.","B":"Heisenberg's uncertainty principle","C":"compton effect","D":"wave-particle paradox"},"answer":"D","explanation":"De Broglie equation, \u03bb = h/mv, is used to descibe the wave properties of matter, which suggests that matter can behave as a wave or particles, thereby leading to the wave-particle paradox.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>22","subject":"Physics","year":"2022","type":"Objective","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"Which of the following statements about a straight current-carrying wire placed in a uniform magnetic field is correct? The wire experiences","images":[],"options":{"A":"maximum motor force if the current reverses its direction","B":"no motor force if it is parallel to the field","C":"no motor force if it is perpendicular to the field","D":"a motor force with constant direction if either the current or the magnetic field is reversed."},"answer":"B","explanation":"If the wire is placed such that the magnetic field is parallel to the length of the wire, the current-carrying wire remains stationary, there would be no force on it.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>23","subject":"Physics","year":"2022","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"Three cells each of emf, 1.1 V, and internal resistance, 2\u03a9, are connected in parallel across a 3\u03a9 resistor. Determine the current in the resistor.","images":[],"options":{"A":"0.90 A","B":"0.39 A","C":"0.30 A","D":"0.01 A"},"answer":"C","explanation":"When cells are connected in parallel, they have same emf = 1.1V   the internal resistances are in parallel, the effective resistance, 1/re = 1/2 + 1/2 + 1/2  1/re = 1+1+12  1/re = 3/2 , re = 2/3 , R = 3\u03a9.  E = I (R+re)  I = E/(R+re) = 1.1/(3 + 2/3)  I = 1.1  \u00d7 3/11  I =3/10 = 0.3A","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>24","subject":"Physics","year":"2022","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"Which of the following statements about electric potential energy is not correct?","images":[],"options":{"A":"The electric potential energy of a positively charged particle increases when it moves to a point of higher potential.","B":"The electric potential energy of a negatively charged particle increases when it moves to a point of lower potential.","C":"The electric potential energy of a positively charged particle decreases when it moves to a point of higher potential.","D":"The work done in taking a charged particle around a closed path in an electric field is zero."},"answer":"C","explanation":"The electric potential energy of a positively charged particle does not decrease when it moves to a point of higher potential","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>25","subject":"Physics","year":"2022","type":"Objective","topic":"ELECTRIC FIELD : SHUNT AND MULTIPLIER","question":"A galvanometer with a full scale deflection of 20 mA is converted to read 8V by connecting a 395\u03a9 resistor in series with it. Determine the internal resistance of the galvanometer.","images":[],"options":{"A":"2.5\u03a9","B":"5.0\u03a9","C":"8.0\u03a9","D":"10.0\u03a9"},"answer":"B","explanation":"The total voltage measured V = 8V, the voltage across the Resistor = v1 =i \u00d7R  the voltage across the galvanometer v2 = i\u00d7r, where r is the internal resistance and i is the current flowing through the circuit(same current flows through the resistor and galvanometer since they are in series) = 20\u00d710-3A= 0.02A  V = v1 + v2  v1 = i\u00d7R = 0.02\u00d7395 = 7.9V  v2 = i\u00d7r = 0.02r  V = 7.9 + 0.02r  8 = 7.9 + 0.02r  0.02r = 8 - 7.9  0.02r = 0.1  r = 0.1/0.02  r = 5\u03a9","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>26","subject":"Physics","year":"2022","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"An inductor of inductance 10H is connected across an a.c circuit source of 50V, 100Hz.  What is the current in the circuit? [\u03c0 = 3.14]","images":[],"options":{"A":"0.200A","B":"0.070A","C":"0.050A","D":"0.008A"},"answer":"D","explanation":"VL = ILXL  XL = 2\u03c0fL  VL = 50V, f = 100Hz, L= 10H  XL = 2\u00d73.14\u00d7100\u00d710 = 6280\u03a9  VL = IL \u00d7 6280  50 = IL \u00d7 6280  IL  = 50/6280  IL = 0.008A","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>27","subject":"Physics","year":"2022","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"The speed of fast moving neutrons in a nuclear reactor can be reduced by using","images":[],"options":{"A":"graphite rods.","B":"concrete shield.","C":"iron rods.","D":"boron rods."},"answer":"A","explanation":"In a nuclear reactor, the speed of fast-moving neutrons can be reduced by using graphite rods. This process is known as moderation. The graphite rods act as a moderator that slows down the speed of the neutrons to sustain the chain reaction at a steady rate.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>28","subject":"Physics","year":"2022","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : RESONANCE","question":"In a series R-L-C circuit at resonance, impedance is","images":[],"options":{"A":"maximum","B":"minimum","C":"capacitive","D":"inductive"},"answer":"B","explanation":"At resonance, maximum current is obtained, current is inversely proportional to impedance, therefore the impedance is minimum at resonance.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>29","subject":"Physics","year":"2022","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"A lamp is rated 240V, 60W, Determine the resistance of the lamp when lit.","images":[],"options":{"A":"120\u03a9","B":"240\u03a9","C":"540\u03a9","D":"960\u03a9"},"answer":"D","explanation":"The resistance of the lamp can be calculated using Ohm's law, which states that the resistance (R) is equal to the voltage (V) squared divided by the power (P). Therefore, R = V^2 / P = (240V)^2 / 60W = 960\u03a9.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>30","subject":"Physics","year":"2022","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"One major reason why electrical appliances in homes are normally earthed is that the","images":[],"options":{"A":"person touching the appliance is safe from electric shock","B":"appliances are maintained at a higher p.d than the earth","C":"appliances are maintained at a lower p.d than the earth","D":"appliances are maintained at the same p.d with that of the earth"},"answer":"A","explanation":"Electrical appliances are earthed to protect users against electric shock,by providing a path for a fault current to flow to earth, it also causes a circuit breaker or fuse to switch off the electric current to the circuit that has fault.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2022>31","subject":"Physics","year":"2022","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"In doping an intrinsic semiconductor to produce a p-type semiconductor,","images":[],"options":{"A":"the semiconductor is heated up.","B":"a donor element is added.","C":"an acceptor element is added.","D":"the semiconductor is connected to a battery."},"answer":"C","explanation":"When a semiconductor is doped with elements from group III of the periodic table like boron(B) and Aluminium(Al), they have 3 valence electron, after forming a covalent bond with the semiconductor which has 4 valence electron, they are left with one electron to attain octet rule, which makes them look for an extra electron to accept.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>32","subject":"Physics","year":"2022","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Arrange the following radiations in order of increasing ionization of air.  I. Alpha  II. Gamma  III. Beta","images":[],"options":{"A":"I","B":"II","C":"II","D":"I"},"answer":"C","explanation":"Gamma has the least ionizing power while Alpha has the highest.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>33","subject":"Physics","year":"2022","type":"Objective","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"If the kinetic energy of an electron is 100eV, what is the wavelength of the de-Broglie wave associated with it ?  [h = 6.6 \u00d7 10-34Js, e = 1.6 \u00d7 10-19C, me = 9.1 \u00d7 10-31kg]","images":[],"options":{"A":"1.22 \u00d7 10-10m","B":"4.10 \u00d7 10-10m","C":"3.90 \u00d7 10-10m","D":"5.50 \u00d7 10-14m"},"answer":"A","explanation":"according to de-Broglie's equation, wavelength \u03bb = h/mv  h and m are given while velocity, v, is not given   kinetic energy,K.E = 1/2mv2  K.E = 100eV = 100 \u00d7 1.6 \u00d7 10-19 = 1.6 \u00d7 10-17  v = \u221a2K.E/me    v  = \u221a2 \u00d71.6\u00d710-17/9.1\u00d710-31  v = \u221a3.2 \u00d7 10-17/9.1 \u00d7 10-31  v = \u221a0.352\u00d71014  v = 0.5933\u00d7107 = 5.933\u00d7106  mv = 9.1 \u00d7 10-31 \u00d7 5.933 \u00d7 106= 5.399\u00d710-24kgms-1  \u03bb = h/mv  \u03bb = 6.6 \u00d7 10-34/5.399\u00d710-24  \u03bb = 1.22 \u00d7 10-10m","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>34","subject":"Physics","year":"2022","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"Gamma rays are produced when","images":[],"options":{"A":"high velocity electrons are abruptly stopped in metals.","B":"energy changes occur within the nuclei of atoms.","C":"energy changes occur within the electronic structure of atoms.","D":"electrons are deflected in very strong magnetic fields."},"answer":"B","explanation":"Gamma rays are produced in the disintegration of radioactive atomic nuclei and in the decay of certain subatomic particles.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>35","subject":"Physics","year":"2022","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"The half-life of a radioactive substance is 15 hours. If at some instance, the sample has a mass of 512g, calculate the time it will take 7/8 of the sample to decay.","images":[],"options":{"A":"15 hours","B":"30 hours","C":"45 hours","D":"60 hours"},"answer":"C","explanation":"How long will it take 7/8 to decay and remain 1/8  it remains 1/2 after 15 hours  it will remain 1/4 after 30 hours  and 1/8 after 45 hours","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>36","subject":"Physics","year":"2022","type":"Objective","topic":"TYPES OF WAVES : TRANSVERSE AND LONGITUDINAL","question":"When the direction of vibration of the particles of a medium is perpendicular to the direction of propagation of a wave, the wave is said to be","images":[],"options":{"A":"longitudinal.","B":"transverse.","C":"mechanical.","D":"a sound wave."},"answer":"B","explanation":"Transverse waves are waves which travel perpendicularly to the direction of the vibrations producing the waves.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2022>37","subject":"Physics","year":"2022","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"A hunter fires a gun at a point 408 m away from a cliff. If he hears an echo 2.4s later, determine the speed of the sound wave.","images":[],"options":{"A":"340 ms-1","B":"380 ms-1","C":"400 ms-1","D":"680 ms-1"},"answer":"A","explanation":"speed of sound after the echo is heard, v = 2 \u00d7 distance/total time distance = 408 m, t = 2.4s  v = 2 \u00d7 408/2.4 = 340 ms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>38","subject":"Physics","year":"2022","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"The distance between the fixed points of a mercury-in-glass thermometer is 30 cm. Determine the temperature when the mercury level is 10.5 cm above the lower fixed point.","images":[],"options":{"A":"28.6 \u2218c","B":"30.0 \u2218c","C":"35.0 \u2218c","D":"40.5 \u2218c"},"answer":"C","explanation":"d1-d2/d-d2= 100-0/t-0    d1 - d2 = 30 cm, d - d2 = 10.5cm    30/10.5 = 100/t    30t = 10.5 \u00d7 100 (multiplying both sides by 10.5t)    t = 1050/30    t = 35 \u2218c","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>39","subject":"Physics","year":"2022","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"Which of the following statements about electromagnetic waves is not correct ?","images":[],"options":{"A":"They carry energy as they travel through space.","B":"They travel with the speed of light.","C":"They are longitudinal.","D":"The electric and magnetic fields are at right angles to each other."},"answer":"C","explanation":"Electromagnetic waves are transverse waves, not longitudinal waves. In transverse waves, the direction of the oscillation is perpendicular to the direction of motion of the wave. In longitudinal waves, the direction of the oscillation is the same as the direction of motion of the wave.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2022>40","subject":"Physics","year":"2022","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"The diameter of a brass ring 30 \u2218c is 50.0 cm. To what temperature must this ring be heated to increase its diameter to 50.29 cm ?  [ linear expansivity of brass = 1.9 \u00d7 10-5 K-1]","images":[],"options":{"A":"152.6 \u2218c","B":"182.6 \u2218c","C":"306.1 \u2218c","D":"335.3 \u2218c"},"answer":"D","explanation":"\u03b1 = l2 - l1/l1(\u03b82 - \u03b81)  l2 = 50.29cm, l1 = 50cm, \u03b81 = 30 \u2218c, \u03b1 = 1.9 \u00d7 10-5  l2 - l1 = 50.29 - 50 = 0.29cm    1.9 \u00d7 10-5 = 0.29/50(\u03b82 - 30)    1.9 \u00d7 10-5 \u00d7 50 \u00d7 (\u03b82 - 30) = 0.29 (multiply both sides by 50(\u03b82 - 30)  (\u03b82 - 30) = 0.29/1.9 \u00d7 10-5 \u00d7 50    (\u03b82 - 30) = 305.2632 \u2218c  \u03b82 = 30 + 305.2632 = 335.3 \u2218c","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>41","subject":"Physics","year":"2022","type":"Objective","topic":"HEAT ENERGY : HEAT TRANSFER","question":"Which of the following concepts is a method of heat transfer that does not require a material medium ?","images":[],"options":{"A":"conduction","B":"Diffusion","C":"Convection","D":"Radiation"},"answer":"D","explanation":"Radiation is the process by which heat is transferred from a hotter place to a cooler place without heating of the intervening medium. Thus no material medium is required.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2022>42","subject":"Physics","year":"2022","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Which of the following statements about light travelling from one material medium to another is not correct?","images":[],"options":{"A":"The refracted angle is less than the incident angle if the the speed is higher in the first material.","B":"It bends away from the normal if the speed is lower in the first material.","C":"Its wavelength does not change.","D":"Its frequency changes."},"answer":"D","explanation":"When light travels from one medium to another, its speed and direction may change, which is a phenomenon known as refraction. However, the frequency of light remains constant. It is the wavelength of light that changes when it enters a different medium, not the frequency. Therefore, the statement \"Its frequency changes.\" is not correct and \"Its wavelength does not change,\" is also incorrect.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>43","subject":"Physics","year":"2022","type":"Objective","topic":"MOTION : CAUSE OF MOTION","question":"The engine of a car provides a forward force of 1240N and the total resistive force on the car is 800N. If the mass of the car is 1220kg, determine the distance the car has to travel from the rest before acquiring a speed of 4ms-1.","images":[],"options":{"A":"44.0m","B":"22.2m","C":"11.1m","D":"5.5m"},"answer":"B","explanation":"F - FR = ma, F = the force pushing the car =1240N, FR = frictional force = 800N, m = mass of the car = 1220kg, a = acceleration.  1240 - 800 = 1220a  440 = 1220a  a = 440/1220    a = 0.3607ms-2  from third equation of motion, v2 = u2 + 2as  u = 0, v = 4ms-1, a = 0.3607ms-2  42 = 2 \u00d7 0.3607 \u00d7 s  s = 16/0.7214    s = 22.1791m = 22.2m","marks":"1","difficulty":"3"},{"id":"objective>Physics>2022>44","subject":"Physics","year":"2022","type":"Objective","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"A quantity of water at 0\u2218C is heated to 30\u2218C. for each degree rise in temperature, its density will","images":[],"options":{"A":"rise steadily.","B":"fall steadily","C":"fall and then rises","D":"rise and then falls"},"answer":"D","explanation":"The density of water increases as the temperature increases until it gets to 4\u2218C and then falls as the temperature increases from 4\u2218C to 30\u2218C (anomalous behaviour of water). water has its highest density at 4\u2218C.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>45","subject":"Physics","year":"2022","type":"Objective","topic":"WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD","question":"A small object of mass 50g is released from a point A. Determine the velocity of the object when it reaches a point B, a vertical distance of 30m below A. [ g= 10ms-2]","images":[],"options":{"A":"1.5ms-1","B":"6.0ms-1","C":"17.3ms-1","D":"24.5ms-1"},"answer":"D","explanation":"from 3rd equation of motion, v2 = u2 + 2gs  u = 0, s = 30m.  v2 = 0 + 2 \u00d7 10 \u00d7 30  v2 = 600  v = \u221a600  v = 24.5 ms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>46","subject":"Physics","year":"2022","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Molecules move in random move within a liquid. The total internal energy of the liquid depends on all of the following except its","images":[],"options":{"A":"temperature","B":"mass","C":"specific heat capacity","D":"melting point"},"answer":"D","explanation":"The total internal energy of a liquid depends on its temperature, mass, and specific heat capacity. However, it does not depend on its melting point. The melting point is a property that describes the temperature at which a substance changes from a solid to a liquid state, but it does not directly affect the internal energy of the substance.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>47","subject":"Physics","year":"2022","type":"Objective","topic":"MOTION : VISCOSITY (FRICTION IN FLUIDS)","question":"The viscosity of a fluid depends on the following factors except the","images":[],"options":{"A":"relative motion between the layers of the fluid","B":"nature of the material of the fluid","C":"surface area of the fluid in contact","D":"normal reaction in the fluid"},"answer":"D","explanation":"The viscosity of a fluid depends on the relative motion between the layers of the fluid and the nature of the material of the fluid. However, it does not depend on the normal reaction in the fluid. The normal reaction is a force that acts perpendicular to the surface of contact and does not affect the viscosity of the fluid.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2022>48","subject":"Physics","year":"2022","type":"Objective","topic":"FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS","question":"Using venier calipers, which of the following readings gives the correct measurement for the length of a rod ?","images":[],"options":{"A":"4.1cm","B":"4.13cm","C":"4.125cm","D":"4.1254cm"},"answer":"B","explanation":"The vernier calipers typically provide readings to a precision of two decimal places in centimeters.    Therefore, the correct measurement for the length of a rod using vernier calipers is: 4.13 cm.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2022>49","subject":"Physics","year":"2022","type":"Objective","topic":"EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS","question":"The basic principle of operation of a beam balance is","images":[],"options":{"A":"Archimedes principle","B":"law of flotation","C":"Hooke's law","D":"principle of moments"},"answer":"D","explanation":"The basic principle of operation of a beam balance is the principle of moments. The principle of moments states that for a body to be in equilibrium, the sum of the clockwise moments about any point must be equal to the sum of the anticlockwise moments about the same point. In a beam balance, the weight of the object being measured is balanced by the weight of a known mass, so that the clockwise and anticlockwise moments are equal.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2022>50","subject":"Physics","year":"2022","type":"Objective","topic":"MOTION : SOLID FRICTION","question":"In which of the following situations is friction not useful ?","images":[],"options":{"A":"Operation of a grinding machine","B":"Walking","C":"Application of brakes","D":"Moving piston in a sleeve"},"answer":"D","explanation":"Friction is useful in grinding machine , Being able to stop while walking is due to friction, friction is also used in the application of brakes to stop a moving vehicle. While friction reduces the effeciency of a moving piston in a sleeve","marks":"1","difficulty":"1"}];